import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect, userEvent, waitFor, within } from 'storybook/test';
import App from './App';
import { mockWikiArticles } from '../.storybook/wikiMockData';

const meta = {
  component: App,
  parameters: {
    layout: 'fullscreen',
  },
  render: () => <App />,
} satisfies Meta<typeof App>;

export default meta;

type Story = StoryObj<typeof meta>;

export const Feed: Story = {
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);

    await waitFor(() =>
      expect(
        canvas.getByRole('heading', { name: mockWikiArticles[0].displaytitle }),
      ).toBeVisible(),
    );
    await expect(canvas.getAllByLabelText(/like article/i).length).toBeGreaterThan(0);
    await expect(
      canvas.getByRole('link', { name: /read more/i }),
    ).toHaveAttribute('href', mockWikiArticles[0].url);
  },
};

export const LoadingState: Story = {
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);

    await waitFor(() => expect(canvas.getByText(/loading/i)).toBeVisible());
    await waitFor(() =>
      expect(
        canvas.getByRole('heading', { name: mockWikiArticles[0].displaytitle }),
      ).toBeVisible(),
    );
  },
};

export const AboutPanel: Story = {
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);

    await waitFor(() =>
      expect(
        canvas.getByRole('heading', { name: mockWikiArticles[0].displaytitle }),
      ).toBeVisible(),
    );
    await userEvent.click(canvas.getByRole('button', { name: /about/i }));
    await expect(
      canvas.getByRole('heading', { name: /about wikitok/i }),
    ).toBeVisible();
    await expect(
      canvas.getByRole('link', { name: /github/i }),
    ).toHaveAttribute('href', 'https://github.com/IsaacGemal/wikitok');
  },
};

export const LikesWorkflow: Story = {
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);

    await waitFor(() =>
      expect(
        canvas.getByRole('heading', { name: mockWikiArticles[0].displaytitle }),
      ).toBeVisible(),
    );
    await userEvent.click(canvas.getAllByLabelText(/like article/i)[0]);
    await userEvent.click(canvas.getByRole('button', { name: /likes/i }));
    await expect(
      canvas.getByRole('heading', { name: /liked articles/i }),
    ).toBeVisible();
    await expect(
      canvas.getByRole('link', { name: mockWikiArticles[0].title }),
    ).toBeVisible();
    await expect(
      canvas.getByRole('button', { name: /export/i }),
    ).toBeVisible();
  },
};

export const LikesSearch: Story = {
  play: async ({ canvasElement }) => {
    const canvas = within(canvasElement);

    await waitFor(() =>
      expect(
        canvas.getByRole('heading', { name: mockWikiArticles[0].displaytitle }),
      ).toBeVisible(),
    );
    const likeButtons = canvas.getAllByLabelText(/like article/i);
    await userEvent.click(likeButtons[0]);
    await userEvent.click(likeButtons[1]);
    await userEvent.click(canvas.getByRole('button', { name: /likes/i }));

    const search = canvas.getByRole('textbox', { name: /search liked articles/i });
    await userEvent.type(search, 'Voyager');

    await expect(
      canvas.getByRole('link', { name: mockWikiArticles[1].title }),
    ).toBeVisible();
    await expect(
      canvas.queryByRole('link', { name: mockWikiArticles[0].title }),
    ).not.toBeInTheDocument();
  },
};

